class Solution:
    def mirrorFrequency(self, s: str) -> int:
        freq = {}
        for ch in s:
            freq[ch] = freq.get(ch, 0) + 1
        def mirror(c):
            if c.isdigit():
                return chr(ord('9') - (ord(c) - ord('0')))
            return chr(ord('z') - (ord(c) - ord('a')))
        seen = set()
        total = 0
        for c in list(freq.keys()):
            m = mirror(c)
            key = tuple(sorted([c, m]))
            if key in seen:
                continue
            seen.add(key)
            if c == m:
                continue
            total += abs(freq.get(c, 0) - freq.get(m, 0))
        return total

