class Solution:
    def mirrorFrequency(self, s: str) -> int:
        freq = [0] * 36
        def idx(c):
            if c.isdigit():
                return 26 + (ord(c) - ord('0'))
            return ord(c) - ord('a')
        for ch in s:
            freq[idx(ch)] += 1
        total = 0
        for i in range(26):
            j = 25 - i
            if i < j:
                total += abs(freq[i] - freq[j])
        for i in range(26, 36):
            d = i - 26
            jd = 9 - d
            j = 26 + jd
            if i < j:
                total += abs(freq[i] - freq[j])
        return total

