var mirrorFrequency = function(s) {
    const freq = new Array(36).fill(0);
    function idx(c) {
        if (c >= '0' && c <= '9') return 26 + (c.charCodeAt(0) - 48);
        return c.charCodeAt(0) - 97;
    }
    for (const ch of s) freq[idx(ch)]++;
    let total = 0;
    for (let i = 0; i < 26; i++) {
        const j = 25 - i;
        if (i < j) total += Math.abs(freq[i] - freq[j]);
    }
    for (let i = 26; i < 36; i++) {
        const d = i - 26;
        const jd = 9 - d;
        const j = 26 + jd;
        if (i < j) total += Math.abs(freq[i] - freq[j]);
    }
    return total;
};
